      for (byte[] candBytes : candidate) {
        //if one is a mismatch, then return false
        if (Arrays.equals(candBytes, toMatchIter.next()) == false){
          return AcceptStatus.NO;
        }
      }
      //we've verified all the bytes
      return AcceptStatus.YES;
    } else {
      return AcceptStatus.NO;
    }

  }

